// Hand-written queries (NOT generated by sqlc).
//
// sqlc is not available in this environment, so artifact queries live here,
// written to match the generated code style: a const SQL string, a Params
// struct, and a method on *Queries using the DBTX interface. The Artifact
// model struct also lives here (models.go is generated).

package db

import (
	"context"

	"github.com/jackc/pgx/v5/pgtype"
)

// Artifact mirrors the artifact table (migration 089): a typed run output
// (metrics/equity/plot/log/dataset/other) uploaded by an agent or user and
// stored in object storage under StorageKey. Meta is freeform JSONB
// (campaign, iteration, symbol, timeframe, ...).
type Artifact struct {
	ID          pgtype.UUID        `json:"id"`
	WorkspaceID pgtype.UUID        `json:"workspace_id"`
	TaskID      pgtype.UUID        `json:"task_id"`
	IssueID     pgtype.UUID        `json:"issue_id"`
	Kind        string             `json:"kind"`
	Name        string             `json:"name"`
	StorageKey  string             `json:"storage_key"`
	SizeBytes   int64              `json:"size_bytes"`
	ContentType string             `json:"content_type"`
	Meta        []byte             `json:"meta"`
	CreatedAt   pgtype.Timestamptz `json:"created_at"`
}

const artifactColumns = `id, workspace_id, task_id, issue_id, kind, name, storage_key, size_bytes, content_type, meta, created_at`

const createArtifact = `-- name: CreateArtifact :one
INSERT INTO artifact (
    id, workspace_id, task_id, issue_id, kind, name, storage_key, size_bytes, content_type, meta
) VALUES (
    $1, $2, $3, $4, $5, $6, $7, $8, $9, COALESCE($10::jsonb, '{}'::jsonb)
)
RETURNING ` + artifactColumns + `
`

type CreateArtifactParams struct {
	ID          pgtype.UUID `json:"id"`
	WorkspaceID pgtype.UUID `json:"workspace_id"`
	TaskID      pgtype.UUID `json:"task_id"`
	IssueID     pgtype.UUID `json:"issue_id"`
	Kind        string      `json:"kind"`
	Name        string      `json:"name"`
	StorageKey  string      `json:"storage_key"`
	SizeBytes   int64       `json:"size_bytes"`
	ContentType string      `json:"content_type"`
	Meta        []byte      `json:"meta"`
}

func (q *Queries) CreateArtifact(ctx context.Context, arg CreateArtifactParams) (Artifact, error) {
	row := q.db.QueryRow(ctx, createArtifact,
		arg.ID,
		arg.WorkspaceID,
		arg.TaskID,
		arg.IssueID,
		arg.Kind,
		arg.Name,
		arg.StorageKey,
		arg.SizeBytes,
		arg.ContentType,
		arg.Meta,
	)
	var i Artifact
	err := row.Scan(
		&i.ID,
		&i.WorkspaceID,
		&i.TaskID,
		&i.IssueID,
		&i.Kind,
		&i.Name,
		&i.StorageKey,
		&i.SizeBytes,
		&i.ContentType,
		&i.Meta,
		&i.CreatedAt,
	)
	return i, err
}

const listArtifactsByTask = `-- name: ListArtifactsByTask :many
SELECT ` + artifactColumns + `
FROM artifact
WHERE task_id = $1 AND workspace_id = $2
ORDER BY created_at DESC
`

type ListArtifactsByTaskParams struct {
	TaskID      pgtype.UUID `json:"task_id"`
	WorkspaceID pgtype.UUID `json:"workspace_id"`
}

// ListArtifactsByTask returns artifacts attached to a task, newest first.
// The workspace predicate is redundant with the caller's scoping check but
// keeps the query safe if the call site changes.
func (q *Queries) ListArtifactsByTask(ctx context.Context, arg ListArtifactsByTaskParams) ([]Artifact, error) {
	rows, err := q.db.Query(ctx, listArtifactsByTask, arg.TaskID, arg.WorkspaceID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []Artifact{}
	for rows.Next() {
		var i Artifact
		if err := rows.Scan(
			&i.ID,
			&i.WorkspaceID,
			&i.TaskID,
			&i.IssueID,
			&i.Kind,
			&i.Name,
			&i.StorageKey,
			&i.SizeBytes,
			&i.ContentType,
			&i.Meta,
			&i.CreatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

const listArtifactsByWorkspace = `-- name: ListArtifactsByWorkspace :many
SELECT ` + artifactColumns + `
FROM artifact
WHERE workspace_id = $1
  AND ($2::text IS NULL OR kind = $2)
  AND ($3::uuid IS NULL OR issue_id = $3)
ORDER BY created_at DESC
LIMIT $4 OFFSET $5
`

type ListArtifactsByWorkspaceParams struct {
	WorkspaceID pgtype.UUID `json:"workspace_id"`
	Kind        pgtype.Text `json:"kind"`
	IssueID     pgtype.UUID `json:"issue_id"`
	Limit       int32       `json:"limit"`
	Offset      int32       `json:"offset"`
}

// ListArtifactsByWorkspace returns workspace artifacts, newest first, with
// optional kind / issue_id filters. NULL filter params disable that filter.
func (q *Queries) ListArtifactsByWorkspace(ctx context.Context, arg ListArtifactsByWorkspaceParams) ([]Artifact, error) {
	rows, err := q.db.Query(ctx, listArtifactsByWorkspace,
		arg.WorkspaceID,
		arg.Kind,
		arg.IssueID,
		arg.Limit,
		arg.Offset,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []Artifact{}
	for rows.Next() {
		var i Artifact
		if err := rows.Scan(
			&i.ID,
			&i.WorkspaceID,
			&i.TaskID,
			&i.IssueID,
			&i.Kind,
			&i.Name,
			&i.StorageKey,
			&i.SizeBytes,
			&i.ContentType,
			&i.Meta,
			&i.CreatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

const getArtifact = `-- name: GetArtifact :one
SELECT ` + artifactColumns + `
FROM artifact
WHERE id = $1 AND workspace_id = $2
`

type GetArtifactParams struct {
	ID          pgtype.UUID `json:"id"`
	WorkspaceID pgtype.UUID `json:"workspace_id"`
}

// GetArtifact is workspace-scoped so a cross-workspace id reads as "not
// found" rather than leaking existence, mirroring GetAttachment.
func (q *Queries) GetArtifact(ctx context.Context, arg GetArtifactParams) (Artifact, error) {
	row := q.db.QueryRow(ctx, getArtifact, arg.ID, arg.WorkspaceID)
	var i Artifact
	err := row.Scan(
		&i.ID,
		&i.WorkspaceID,
		&i.TaskID,
		&i.IssueID,
		&i.Kind,
		&i.Name,
		&i.StorageKey,
		&i.SizeBytes,
		&i.ContentType,
		&i.Meta,
		&i.CreatedAt,
	)
	return i, err
}

const deleteArtifact = `-- name: DeleteArtifact :exec
DELETE FROM artifact
WHERE id = $1 AND workspace_id = $2
`

type DeleteArtifactParams struct {
	ID          pgtype.UUID `json:"id"`
	WorkspaceID pgtype.UUID `json:"workspace_id"`
}

func (q *Queries) DeleteArtifact(ctx context.Context, arg DeleteArtifactParams) error {
	_, err := q.db.Exec(ctx, deleteArtifact, arg.ID, arg.WorkspaceID)
	return err
}
